<?php namespace App\Models; use App\Models\Ecommerce\StoreLocation; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\SoftDeletes; class Expense extends Model {use SoftDeletes; protected $fillable=['expense_no','store_location_id','expense_category_id','expense_date','title','amount','remark','receipt_path','created_by','updated_by']; protected function casts():array{return ['expense_date'=>'date','amount'=>'decimal:2'];} public function branch(){return $this->belongsTo(StoreLocation::class,'store_location_id');} public function category(){return $this->belongsTo(ExpenseCategory::class,'expense_category_id');} public function creator(){return $this->belongsTo(User::class,'created_by');} }
